files.content:
.onmark-film,
.onmark-scene,
.onmark-shot {
  width: 100%;
  height: 100%;
}

.onmark-shot {
  position: relative;
  overflow: hidden;
  background: #050505;
}

.onmark-video {
  width: 100%;
  height: 100%;
  object-fit: cover;
  filter: brightness(0.48);
}

.onmark-title {
  position: absolute;
  left: 7vw;
  bottom: 9vh;
  margin: 0;
  color: #fff;
  font: 700 clamp(3rem, 8vw, 8rem)/0.95 sans-serif;
}

import { gsapMotion } from "onmark/motion/gsap";

export const motion = gsapMotion({
  title({ element, timeline }) {
    timeline.from(element, {
      opacity: 0,
      y: 36,
      duration: 0.45,
      ease: "power2.out",
    });
  },
});

.onmark-film,
.onmark-scene,
.onmark-shot {
  width: 100%;
  height: 100%;
}

.onmark-shot {
  position: relative;
  overflow: hidden;
}

#story {
  background: #ff5a5f;
}

#compile {
  background: #635bff;
}

#render {
  background: #00a878;
}

.onmark-video {
  width: 100%;
  height: 100%;
  object-fit: cover;
  mix-blend-mode: multiply;
}

.onmark-title {
  position: absolute;
  left: 7vw;
  bottom: 8vh;
  margin: 0;
  color: #fff;
  font: 700 clamp(4rem, 12vw, 11rem)/0.9 sans-serif;
}

import { gsapMotion } from "onmark/motion/gsap";

export const motion = gsapMotion({
  shot({ element, timeline }) {
    timeline.fromTo(
      element,
      { clipPath: "inset(0 100% 0 0)" },
      {
        clipPath: "inset(0 0% 0 0)",
        duration: 0.55,
        ease: "power2.inOut",
      },
    );
  },
});

.onmark-film,
.onmark-scene,
.onmark-shot {
  width: 100%;
  height: 100%;
}

.onmark-shot {
  position: relative;
  overflow: hidden;
  background: #111;
}

.onmark-video {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.onmark-title {
  position: absolute;
  left: 7vw;
  bottom: 22vh;
  margin: 0;
  color: #fff;
  font: 800 clamp(4rem, 10vw, 9rem)/1 sans-serif;
}

.onmark-call-to-action {
  position: absolute;
  left: 7vw;
  bottom: 9vh;
  padding: 1rem 2rem;
  border-radius: 999px;
  background: #e32636;
  color: #fff;
  font: 700 1.4rem/1 sans-serif;
}

import { gsapMotion } from "onmark/motion/gsap";

export const motion = gsapMotion({
  callToAction({ element, timeline }) {
    timeline.from(element, {
      opacity: 0,
      scale: 0.8,
      duration: 0.4,
      ease: "back.out(1.7)",
    });
  },
});

import { definePresentation } from "@onmark/authoring";
import { h } from "@onmark/runtime";

export const presentation = definePresentation({
  shot() {
    return h(
      "h1",
      { className: "onmark-title" },
      "Write ",
      h("span", { className: "accent" }, "native."),
      " Render exact.",
    );
  },
});

.onmark-film,
.onmark-scene,
.onmark-shot {
  width: 100%;
  height: 100%;
}

.onmark-shot {
  position: relative;
  overflow: hidden;
  background: #080808;
}

.onmark-video {
  width: 100%;
  height: 100%;
  object-fit: cover;
  filter: brightness(0.42);
}

.onmark-title {
  position: absolute;
  left: 7vw;
  bottom: 9vh;
  margin: 0;
  color: #fff;
  font: 700 clamp(3rem, 8vw, 8rem)/1 sans-serif;
}

.onmark-title .accent {
  color: #b7ff3c;
}

import { gsapMotion } from "onmark/motion/gsap";

export const motion = gsapMotion({
  title({ element, timeline }) {
    timeline.from(element, {
      opacity: 0,
      y: 24,
      duration: 0.45,
      ease: "power2.out",
    });
  },
  selectors: {
    ".accent"({ element, timeline }) {
      timeline.from(element, {
        opacity: 0,
        scale: 0.7,
        duration: 0.35,
        ease: "back.out(1.8)",
      });
    },
  },
});

import { definePresentation } from "@onmark/authoring";
import { h } from "@onmark/runtime";

export const presentation = definePresentation({
  shot() {
    return h("div", {
      className: "grid",
      "aria-hidden": "true",
    });
  },
});

.onmark-film,
.onmark-scene,
.onmark-shot {
  width: 100%;
  height: 100%;
}

.onmark-shot {
  position: relative;
  overflow: hidden;
  background: #070b14;
}

.onmark-video {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.grid {
  position: absolute;
  inset: 0;
  z-index: 1;
  background-image:
    linear-gradient(rgba(94, 234, 212, 0.28) 1px, transparent 1px),
    linear-gradient(90deg, rgba(94, 234, 212, 0.28) 1px, transparent 1px);
  background-size: 64px 64px;
  pointer-events: none;
}

.onmark-title {
  position: absolute;
  z-index: 2;
  left: 7vw;
  bottom: 9vh;
  margin: 0;
  color: #fff;
  font: 800 clamp(4rem, 11vw, 10rem)/0.95 sans-serif;
}

import { gsapMotion } from "onmark/motion/gsap";

export const motion = gsapMotion({
  selectors: {
    ".grid"({ element, timeline }) {
      timeline.from(element, {
        opacity: 0,
        duration: 0.7,
        ease: "power1.out",
      });
    },
  },
});
